class Tal():

  def __init__(self, tal):
    self.tal = tal

  def __str__(self):
    return "från str: " + str(self.tal)

  def __repr__(self):
    return "från repr: " + str(self.tal)

lista=[]
for i in range(5):
  objekt = Tal(i)
  lista.append(objekt)

print(lista) #Här används repr, om den inte finns kommer du få var den finns i minnet: <__main__.Tal object at 0x7f19b2c9fd90>
for element in lista:
  print(element) #Här str, om de inte finns repr
